define({"topics":[{"title":"Electric vehicle","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Demonstration of the Electric Vehicle example model, featuring an electric vehicle with a fast DC charger. Both the EV and the charger are represented with detailed power electronics models.<\/span><\/p>","href":"t-an001\/References\/electric_vehicle.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e108","topics":[]},{"title":"Electric vehicle charging according to standard IEC62196 – mode 3 ","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Demonstration of Electric vehicle AC charging using an     IEC62196 Type 2 connector. Communication between the EV charger and the EV is     performed using PWM signalization over Control Pilot as per IEC 61851-1 and J1772.<\/span><\/p>","href":"t-an001\/References\/electric_vehicle_ac_charging.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e120","topics":[]}]});